use std::collections::HashMap;

struct ResultData {
    kind: String,
    payload: HashMap<String, String>,
}

fn process_results(items: &[ResultData]) -> usize {
    let mut count = 0;
    for item in items.iter() {
        match item.kind.as_str() {
            "success" => {
                if let Some(data) = item.payload.get("id") {
                    println!("Processed success for ID: {}", data);
                    count += 1;
                }
            },
            "failure" => {
                if let Some(message) = item.payload.get("msg") {
                    println!("Caught failure: {}", message);
                }
            },
            _ => {
                println!("Unknown result type encountered.");
            }
        }
    }
    count
}

fn main() {
    let mut map1 = HashMap::new();
    map1.insert("key".to_string(), "value1".to_string());

    let mut map2 = HashMap::new();
    map2.insert("msg".to_string(), "Network timeout".to_string());

    let results = vec![ 
        ResultData {
            kind: "success".to_string(),
            payload: map1,
        },
        ResultData {
            kind: "failure".to_string(),
            payload: map2.clone(),
        },
        ResultData {
            kind: "unknown".to_string(),
            payload: HashMap::new(),
        }
    ];

    let total = process_results(&results);
    println!("nTotal successful items counted: {}", total);
}

use std::collections::HashMap;
use std::net::SocketAddr;

struct ConnectionState {
    sequence_id: u32,
    packet_count: usize,
    last_activity: std::time::Instant,
}

impl ConnectionState {
    fn new(addr: SocketAddr) -> Self {
        ConnectionState {
            sequence_id: 1,
            packet_count: 0,
            last_activity: std::time::Instant::now(),
        }
    }
}

struct ProxySession {
    connections: HashMap<SocketAddr, ConnectionState>,
}

impl ProxySession {
    fn new() -> Self {
        ProxySession {
            connections: HashMap::new(),
        }
    }

    fn register_connection(&mut self, addr: SocketAddr) -> &mut ConnectionState {
        if !self.connections.contains_key(&addr) {
            let state = ConnectionState::new(addr);
            self.connections.insert(addr, state);
        }
        self.connections.get_mut(&addr).unwrap()
    }

    fn process_packet(&mut self, addr: SocketAddr, header_data: &[u8], payload_size: usize) -> bool {
        let state = match self.connections.get_mut(&addr) {
            Some(s) => s,
            None => return false,
        };

        if header_data.starts_with(&[0xAA, 0xBB]) && payload_size > 10 {
            state.packet_count += 1;
            state.sequence_id = state.sequence_id.wrapping_add(1);
            println!("Matched pattern for {}: Processed packet, count updated.", addr);
            true
        } else if header_data.len() < 2 {
            false
        } else {
            state.packet_count += 1;
            state.sequence_id = state.sequence_id.wrapping_add(1);
            println!("Generic packet for {}: Processed normally.", addr);
            true
        }
    }
}

fn main() {
    let mut session = ProxySession::new();
    let addr1: SocketAddr = "127.0.0.1:8080".parse().unwrap();
    let addr2: SocketAddr = "127.0.0.1:9000".parse().unwrap();

    session.register_connection(addr1);
    session.register_connection(addr2);

    let header_match = &[0xAA, 0xBB];
    let payload_ok = vec![0u8; 15];

    session.process_packet(addr1, header_match, payload_ok.len());
    session.process_packet(addr2, &[], 5);
    session.process_packet(addr1, &[0xCC, 0xDD], vec![1u8].into_boxed_slice().len());
}

use std::collections::VecDeque;

struct Message {
    kind: MessageKind,
    data: String,
}

enum MessageKind {
    TextChunk,
    HeaderBlock(String),
    EndSignal
}

fn process_message(msg: &Message) -> Result<String, &'static str> {
    match &msg.kind {
        MessageKind::TextChunk => Ok(format!("Successfully processed simple text data.")),
        MessageKind::HeaderBlock(header) => {
            if header.contains("AUTH") {
                Ok(format!("Authenticated and passed through header: {}", &header[..10].to_string()))
            } else {
                Err("Missing required authorization header.")
            }
        },
        MessageKind::EndSignal => Ok("Received end signal, closing connection.".to_string()),
    }
}

fn main() {
    let text_msg = Message { kind: MessageKind::TextChunk, data: "GET /index.html".to_string() };
    let auth_header_msg = Message { kind: MessageKind::HeaderBlock("TYPE=HTTP/2; AUTH=BearerToken123".to_string()), data: String::new() };
    let bad_header_msg = Message { kind: MessageKind::HeaderBlock("TYPE=PLAIN; ID=xyz".to_string()), data: String::new() };
    let end_msg = Message { kind: MessageKind::EndSignal, data: String::new() };

    println!("n--- Test 1 ---n{}", process_message(&text_msg).unwrap());
    println!("n--- Test 2 ---n{}", process_message(&auth_header_msg).unwrap());
    match process_message(&bad_header_msg) {
        Ok(s) => println!("Unexpected success: {}", s),
        Err(e) => println!("Caught expected error for bad header: {}", e),
    }
    println!("n--- Test 3 ---n{}", process_message(&end_msg).unwrap());
}

use std::collections::HashMap;
use std::time::{Duration, Instant};

struct RateLimiter {
    storage: HashMap<String, (Instant, u32)>, 
    limit_duration: Duration,
    max_requests: u32,
}

impl RateLimiter {
    fn new(limit_duration: Duration, max_requests: u32) -> Self {
        RateLimiter {
            storage: HashMap::new(),
            limit_duration,
            max_requests,
        }
    }

    fn check_and_increment(&mut self, client_ip: &str) -> bool {
        let now = Instant::now();

        if let Some((last_reset, count)) = self.storage.get_mut(client_ip) {
            if now.duration_since(*last_reset) > self.limit_duration {
                *last_reset = now;
                *count = 1;
                return true;
            }

            if *count < self.max_requests {
                *count += 1;
                return true;
            } else {
                false
            }
        } else {
            self.storage.insert(client_ip.to_string(), (now, 1));
            true
        }
    }

    fn is_allowed(&mut self, client_ip: &str) -> bool {
        self.check_and_increment(client_ip)
    }
}

use std::collections::HashMap;

struct DataBatcher {
    storage: HashMap<i32, String>,
}

impl DataBatcher {
    fn new() -> Self {
        DataBatcher { storage: HashMap::new() }
    }

    fn set_data(&mut self, id: i32, data: String) {
        self.storage.insert(id, data);
    }

    fn load_batch(&self, ids: &[i32]) -> HashMap<i32, Option<String>> {
        let mut results = HashMap::new();
        for &id in ids {
            results.insert(id, self.storage.get(&id).cloned());
        }
        results
    }
}

fn main() {
    let mut batcher = DataBatcher::new();
    batcher.set_data(101, "User Alpha's Object".to_string());
    batcher.set_data(205, "Product Beta's Object".to_string());
    batcher.set_data(312, "Service Gamma's Object".to_string());

    let required_ids = vec![101, 312, 999];
    let loaded_data = batcher.load_batch(&required_ids);

    for id in required_ids {
        match loaded_data.get(&id) {
            Some(Some(obj)) => println!("Successfully loaded object for ID {}: {}", id, obj),
            Some(None) => println!("Object not found for ID {}.", id),
            _ => {} 
        }
    }
}
